INSERT INTO recruiters (id, user_id, company_name, company_website, company_address, company_city, company_description, company_phone, company_size, company_type, founded_year, industry, benefits, rating, review_count, logo_url, cover_image_url, tax_code, business_license_url, linkedin_url, facebook_url, contact_name, contact_email, contact_phone, status, rejection_note, quota_job_post, quota_cv_views, created_at, updated_at, deleted, source_page) VALUES
  ('recruiter-sapo', 'user-recruiter-001', 'Công ty cổ phần Công nghệ Sapo', 'https://tuyendung.sapo.vn/', 'Tầng 6, Tòa Ladeco, 266 Đội Cấn, Quận Ba Đình, TP Hà Nội', 'Hà Nội', 'Sapo là nền tảng quản lý bán hàng hợp kênh được sử dụng rộng rãi tại Việt Nam. Doanh nghiệp được thành lập năm 2008, tập trung vào công nghệ bán lẻ, thương mại điện tử và các giải pháp số giúp nhà bán hàng tăng trưởng doanh thu.', '0765588715', '500-1000 nhân viên', 'PRODUCT_COMPANY', 2008, 'IT - Phần mềm', '["Thu nhập cạnh tranh theo năng lực", "Môi trường công nghệ tăng trưởng nhanh", "Đào tạo nội bộ và lộ trình thăng tiến rõ ràng"]', 4.7, 40, 'https://smartcv-bucket-411307360545-ap-southeast-2-an.s3.ap-southeast-2.amazonaws.com/avatars/sapo/sapo.jpg', NULL, '0103243195', NULL, 'https://www.linkedin.com/company/sapo-tech/', 'https://www.facebook.com/sapo.vn', 'Sapo Talent Acquisition', 'tuyendung@sapo.vn', '0765588715', 'APPROVED', NULL, 10, 50, '2026-06-20 10:00:00', '2026-06-20 10:00:00', FALSE, 'https://www.topcv.vn/brand/sapovn?id=11698'),
  ('recruiter-vnpay', 'user-recruiter-002', 'Công ty CP Giải pháp Thanh toán Việt Nam (VNPAY)', 'https://vnpay.vn/', 'Hà Nội, Việt Nam', 'Hà Nội', 'VNPAY thành lập tháng 03/2007, là doanh nghiệp hàng đầu về thanh toán điện tử tại Việt Nam. Công ty phát triển sản phẩm trong các lĩnh vực tài chính ngân hàng, công nghệ thông tin và viễn thông.', NULL, '2000+ nhân sự', 'FINTECH', 2007, 'Tài chính - Công nghệ thanh toán', '["Dự án quy mô lớn trong fintech", "Môi trường chuyên nghiệp, chú trọng sáng tạo", "Làm việc cùng hệ sinh thái ngân hàng và thanh toán số"]', 4.6, 18, 'https://smartcv-bucket-411307360545-ap-southeast-2-an.s3.ap-southeast-2.amazonaws.com/avatars/vnpay/vnpay.jpg', NULL, NULL, NULL, 'https://www.linkedin.com/company/vnpay/', 'https://www.facebook.com/VNPAYQR/', 'VNPAY Recruitment', 'recruitment@vnpay.vn', '0901002003', 'APPROVED', NULL, 10, 50, '2026-06-20 10:00:00', '2026-06-20 10:00:00', FALSE, 'https://www.topcv.vn/cong-ty/cong-ty-cp-giai-phap-thanh-toan-viet-nam-vnpay/200858.html'),
  ('recruiter-novaon', 'user-recruiter-003', 'Tập Đoàn Novaon', 'https://novaon.net', 'Hà Nội, Việt Nam', 'Hà Nội', 'Novaon được thành lập năm 2006, hoạt động trong ba mảng chính gồm tiếp thị số, công nghiệp và thương mại điện tử. Doanh nghiệp sở hữu hệ sinh thái sản phẩm công nghệ và phục vụ hàng chục nghìn khách hàng.', NULL, '1000+ nhân sự', 'TECH_GROUP', 2006, 'Digital Marketing / IT - Phần mềm', '["Hệ sinh thái công nghệ và marketing số lớn", "Nhiều cơ hội chuyển dự án và phát triển chuyên môn", "Môi trường tăng trưởng nhanh, hướng tới thị trường quốc tế"]', 4.5, 27, 'https://smartcv-bucket-411307360545-ap-southeast-2-an.s3.ap-southeast-2.amazonaws.com/avatars/novaon/novaon.png', NULL, NULL, NULL, 'https://www.linkedin.com/company/novaon-group/', 'https://www.facebook.com/NovaonGroup', 'Novaon Talent Team', 'talent@novaon.net', '0901002004', 'APPROVED', NULL, 10, 50, '2026-06-20 10:00:00', '2026-06-20 10:00:00', FALSE, 'https://www.topcv.vn/cong-ty/tap-doan-novaon/201092.html'),
  ('recruiter-icheck', 'user-recruiter-004', 'Công ty cổ phần iCheck', 'https://careers.icheck.com.vn/', 'Hà Nội, Việt Nam', 'Hà Nội', 'iCheck thành lập năm 2015, phát triển từ ứng dụng quét mã sang hệ sinh thái giải pháp số hóa sản phẩm, minh bạch thông tin và hỗ trợ chuyển đổi số cho doanh nghiệp.', NULL, '200-500 nhân sự', 'PRODUCT_COMPANY', 2015, 'IT - Phần mềm / Chuyển đổi số', '["Sản phẩm công nghệ có tác động thực tế đến doanh nghiệp và người tiêu dùng", "Môi trường làm việc dữ liệu và tăng trưởng", "Định hướng chuyển đổi số bài bản"]', 4.4, 6, 'https://smartcv-bucket-411307360545-ap-southeast-2-an.s3.ap-southeast-2.amazonaws.com/avatars/icheck/icheck.jpg', NULL, NULL, NULL, 'https://www.linkedin.com/company/icheck-corporation/', 'https://www.facebook.com/iCheckCorporation', 'iCheck Hiring Team', 'careers@icheck.com.vn', '0901002005', 'PENDING', NULL, 10, 10, '2026-06-20 10:00:00', '2026-06-20 10:00:00', FALSE, 'https://www.topcv.vn/cong-ty/cong-ty-co-phan-icheck/1319.html'),
  ('recruiter-pjsb', 'user-recruiter-005', 'CÔNG TY TNHH PJSB', 'https://www.topcv.vn/cong-ty/cong-ty-tnhh-pjsb/225311.html', 'Hà Nội, Việt Nam', 'Hà Nội', 'PJSB thành lập năm 2023, hoạt động trong lĩnh vực phân phối thực phẩm chức năng, mỹ phẩm và các sản phẩm chăm sóc sức khỏe, sắc đẹp.', NULL, '100-499 nhân viên', 'DISTRIBUTOR', 2023, 'Bán lẻ - Hàng tiêu dùng - FMCG', '["Môi trường phát triển thị trường nhanh", "Sản phẩm chăm sóc sức khỏe và làm đẹp chính hãng", "Định hướng mở rộng hệ thống phân phối toàn quốc"]', 4.1, 3, 'https://smartcv-bucket-411307360545-ap-southeast-2-an.s3.ap-southeast-2.amazonaws.com/avatars/pjsb/pjsb.jpg', NULL, NULL, NULL, NULL, NULL, 'PJSB HR Team', 'hr@pjsb.vn', '0901002006', 'PENDING', NULL, 10, 10, '2026-06-20 10:00:00', '2026-06-20 10:00:00', FALSE, 'https://www.topcv.vn/cong-ty/cong-ty-tnhh-pjsb/225311.html');
